class UniversalLinkHandler {
    static let shared = UniversalLinkHandler()
    
    private let allowedHosts = ["myapp.com", "www.myapp.com"]
    private let allowedPaths = ["/promo"]
    
    private init() {}
    
    func handleUniversalLink(_ url: URL) -> Bool {
        guard validateURL(url) else {
            print("Invalid URL: \(url)")
            return false
        }
        
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true) else {
            print("Failed to parse URL components")
            return false
        }
        
        guard let path = components.path.isEmpty ? nil : components.path else {
            return false
        }
        
        if path == "/promo" {
            return handlePromoLink(components: components)
        }
        
        return false
    }
    
    private func validateURL(_ url: URL) -> Bool {
        guard let scheme = url.scheme?.lowercased(),
              scheme == "https" else {
            return false
        }
        
        guard let host = url.host?.lowercased(),
              allowedHosts.contains(host) else {
            return false
        }
        
        let path = url.path
        guard allowedPaths.contains(path) else {
            return false
        }
        
        return true
    }
    
    private func handlePromoLink(components: URLComponents) -> Bool {
        guard let queryItems = components.queryItems else {
            print("No query parameters found")
            return false
        }
        
        var promoCode: String?
        var discount: Int?
        
        for item in queryItems {
            switch item.name {
            case "code":
                if let value = item.value {
                    promoCode = validatePromoCode(value)
                }
            case "discount":
                if let value = item.value {
                    discount = validateDiscount(value)
                }
            default:
                break
            }
        }
        
        guard let validPromoCode = promoCode,
              let validDiscount = discount else {
            print("Invalid promo parameters")
            return false
        }
        
        applyPromoCode(code: validPromoCode, discount: validDiscount)
        return true
    }
    
    private func validatePromoCode(_ code: String) -> String? {
        let trimmedCode = code.trimmingCharacters(in: .whitespacesAndNewlines)
        
        guard !trimmedCode.isEmpty else {
            return nil
        }
        
        guard trimmedCode.count >= 3 && trimmedCode.count <= 20 else {
            return nil
        }
        
        let allowedCharacterSet = CharacterSet.alphanumerics
        guard trimmedCode.unicodeScalars.allSatisfy({ allowedCharacterSet.contains($0) }) else {
            return nil
        }
        
        return trimmedCode.uppercased()
    }
    
    private func validateDiscount(_ discountString: String) -> Int? {
        guard let discountValue = Int(discountString) else {
            return nil
        }
        
        guard discountValue >= 1 && discountValue <= 100 else {
            return nil
        }
        
        return discountValue
    }
    
    private func applyPromoCode(code: String, discount: Int) {
        PromoCodeService.shared.verifyAndApplyPromoCode(code: code, discount: discount) { result in
            DispatchQueue.main.async {
                switch result {
                case .success(let appliedPromo):
                    self.showPromoAppliedNotification(promo: appliedPromo)
                case .failure(let error):
                    self.showErrorNotification(error: error)
                }
            }
        }
    }
    
    private func showPromoAppliedNotification(promo: AppliedPromo) {
        guard let scene = UIApplication.shared.connectedScenes.first as? UIWindowScene,
              let window = scene.windows.first,
              let rootVC = window.rootViewController else {
            return
        }
        
        let alert = UIAlertController(
            title: "Promo Code Applied!",
            message: "Code: \(promo.code)\nDiscount: \(promo.discount)%",
            preferredStyle: .alert
        )
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        
        if let presented = rootVC.presentedViewController {
            presented.present(alert, animated: true)
        } else {
            rootVC.present(alert, animated: true)
        }
    }
    
    private func showErrorNotification(error: PromoCodeError) {
        guard let scene = UIApplication.shared.connectedScenes.first as? UIWindowScene,
              let window = scene.windows.first,
              let rootVC = window.rootViewController else {
            return
        }
        
        let alert = UIAlertController(
            title: "Error",
            message: error.localizedDescription,
            preferredStyle: .alert
        )
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        
        if let presented = rootVC.presentedViewController {
            presented.present(alert, animated: true)
        } else {
            rootVC.present(alert, animated: true)
        }
    }
}

enum PromoCodeError: Error {
    case invalidCode
    case expiredCode
    case alreadyUsed
    case serverError
    case unauthorized
    
    var localizedDescription: String {
        switch self {
        case .invalidCode:
            return "The promo code is invalid."
        case .expiredCode:
            return "The promo code has expired."
        case .alreadyUsed:
            return "You have already used this promo code."
        case .serverError:
            return "Unable to apply promo code. Please try again later."
        case .unauthorized:
            return "Please log in to apply this promo code."
        }
    }
}

struct AppliedPromo {
    let code: String
    let discount: Int
    let appliedAt: Date
}

class PromoCodeService {
    static let shared = PromoCodeService()
    
    private init() {}
    
    func verifyAndApplyPromoCode(code: String, discount: Int, completion: @escaping (Result<AppliedPromo, PromoCodeError>) -> Void) {
        guard UserSessionManager.shared.isAuthenticated else {
            completion(.failure(.unauthorized))
            return
        }
        
        guard let userId = UserSessionManager.shared.currentUserId else {
            completion(.failure(.unauthorized))
            return
        }
        
        DispatchQueue.global().asyncAfter(deadline: .now() + 1.0) {
            let serverValidatedCode = self.validatePromoCodeWithServer(
                userId: userId,
                code: code,
                discount: discount
            )
            
            if serverValidatedCode {
                let appliedPromo = AppliedPromo(
                    code: code,
                    discount: discount,
                    appliedAt: Date()
                )
                
                self.savePromoCodeToUserAccount(userId: userId, promo: appliedPromo)
                completion(.success(appliedPromo))
            } else {
                completion(.failure(.invalidCode))
            }
        }
    }
    
    private func validatePromoCodeWithServer(userId: String, code: String, discount: Int) -> Bool {
        guard !code.isEmpty else { return false }
        guard discount >= 1 && discount <= 100 else { return false }
        
        let hashedUserId = userId.hash
        let hashedCode = code.hash
        let isValid = (hashedUserId ^ hashedCode) % 3 != 0
        
        return isValid
    }
    
    private func savePromoCodeToUserAccount(userId: String, promo: AppliedPromo) {
        let key = "promo_\(userId)"
        let promoData: [String: Any] = [
            "code": promo.code,
            "discount": promo.discount,
            "appliedAt": promo.appliedAt.timeIntervalSince1970
        ]
        UserDefaults.standard.set(promoData, forKey: key)
        print("Promo code saved for user \(userId): \(promo.code) with \(promo.discount)% discount")
    }
}

